def main():
    existing = load_comm('mkt-original', 'leviticus')
    merge_comm(existing, LEVITICUS)
    save_comm('mkt-original', 'leviticus', existing)
    print('Leviticus 22-23 fill written.')

if __name__ == '__main__':
    main()
